def ticket_price(age):
    if age < 5:
        return 0
    if age <= 17:
        return 8
    if age <= 64:
        return 12
    return 6

def count_short_words(words, max_length):
    count = 0
    for word in words:
        if len(word) <= max_length:
            count += 1
    return count

def divisible_by(numbers, divisor):
    result = []
    for number in numbers:
        if number % divisor == 0:
            result.append(number)
    return result

def password_strength(password):
    if len(password) < 8:
        return "weak"
    has_digit = False
    for char in password:
        if char.isdigit():
            has_digit = True
            break
    if has_digit:
        return "strong"
    return "medium"

def top_student(records):
    if not records:
        return None
    best = records[0]
    for record in records[1:]:
        if record["score"] > best["score"]:
            best = record
    return best["name"]

def char_frequency(text):
    counts = {}
    for char in text.lower():
        if char == " ":
            continue
        counts[char] = counts.get(char, 0) + 1
    return counts

def diagonal_sum(matrix):
    total = 0
    for index in range(len(matrix)):
        total += matrix[index][index]
    return total

class Gradebook:
    def __init__(self):
        self.scores = []

    def add_score(self, score):
        self.scores.append(score)

    def average(self):
        if not self.scores:
            return None
        return sum(self.scores) / len(self.scores)

    def highest(self):
        if not self.scores:
            return None
        return max(self.scores)

def is_balanced_parentheses(text):
    balance = 0
    for char in text:
        if char == "(":
            balance += 1
        elif char == ")":
            balance -= 1
            if balance < 0:
                return False
    return balance == 0

def recommend_weakest_exercise(mastery, exercises):
    if not mastery or not exercises:
        return None
    weakest_kc = None
    weakest_score = None
    for kc_id, score in mastery.items():
        if weakest_score is None or score < weakest_score:
            weakest_kc = kc_id
            weakest_score = score
    for exercise in exercises:
        if weakest_kc in exercise["kc_tags"]:
            return exercise["id"]
    return None
